INSERT INTO `news_article` (`article_id`, `publish_ts`, `title`, `content`, `source`, `sector_tag`, `ai_summary`, `summarized`, `ai_sentiment`, `sentiment_score`, `sentiment_done`, `ai_extract`, `extracted`, `ai_method`) VALUES
  ('INV001', '2026-04-01 09:01:00', 'Multi-asset outlook: investors rotate from cash into duration, quality equities and gold hedges', 'Global portfolio managers are beginning the second quarter with a more balanced risk budget after nearly two years of unusually high cash allocations. The central investment debate is no longer whether interest rates will remain restrictive, but how quickly inflation can fall without forcing a sharp decline in corporate earnings. Several large asset allocators now expect policy rates in the United States and Europe to move lower over the next twelve months, creating a more constructive backdrop for intermediate duration bonds and high quality equities. The change is meaningful because money market funds still hold a record level of assets, and even a modest rotation out of cash could provide steady demand for government bonds, investment grade credit and companies with visible free cash flow.
